package com.example.api;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.validation.Valid;
import java.util.Collections;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@SpringBootApplication
@RestController
@RequestMapping("/api")
public class SecureApiApplication {

    private static final Logger logger = LoggerFactory.getLogger(SecureApiApplication.class);
    private final Map<String, Object> dataStore = new ConcurrentHashMap<>();

    public static void main(String[] args) {
        SpringApplication.run(SecureApiApplication.class, args);
        logger.info("Secure API Application started successfully");
    }

    @GetMapping("/health")
    public ResponseEntity<Map<String, String>> healthCheck() {
        logger.info("Health check endpoint accessed");
        return ResponseEntity.ok(Collections.singletonMap("status", "healthy"));
    }

    @PostMapping("/data")
    public ResponseEntity<Map<String, String>> createData(@Valid @RequestBody DataRequest request) {
        logger.info("Creating data for key: {}", request.getKey());
        try {
            if (request.getKey() == null || request.getKey().trim().isEmpty()) {
                logger.warn("Invalid key provided in create request");
                return ResponseEntity.badRequest().build();
            }
            dataStore.put(request.getKey(), request.getValue());
            logger.info("Data created successfully for key: {}", request.getKey());
            return ResponseEntity.status(HttpStatus.CREATED)
                    .body(Collections.singletonMap("message", "Data created successfully"));
        } catch (Exception e) {
            logger.error("Error creating data for key: {}", request.getKey(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    @GetMapping("/data/{key}")
    public ResponseEntity<Object> getData(@PathVariable String key) {
        logger.info("Retrieving data for key: {}", key);
        try {
            if (key == null || key.trim().isEmpty()) {
                logger.warn("Empty key provided in get request");
                return ResponseEntity.badRequest().build();
            }
            Object data = dataStore.get(key);
            if (data == null) {
                logger.warn("Data not found for key: {}", key);
                return ResponseEntity.notFound().build();
            }
            logger.info("Data retrieved successfully for key: {}", key);
            return ResponseEntity.ok(data);
        } catch (Exception e) {
            logger.error("Error retrieving data for key: {}", key, e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    @PutMapping("/data/{key}")
    public ResponseEntity<Map<String, String>> updateData(@PathVariable String key, @Valid @RequestBody DataRequest request) {
        logger.info("Updating data for key: {}", key);
        try {
            if (key == null || key.trim().isEmpty()) {
                logger.warn("Empty key provided in update request");
                return ResponseEntity.badRequest().build();
            }
            dataStore.put(key, request.getValue());
            logger.info("Data updated successfully for key: {}", key);
            return ResponseEntity.ok(Collections.singletonMap("message", "Data updated successfully"));
        } catch (Exception e) {
            logger.error("Error updating data for key: {}", key, e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    @DeleteMapping("/data/{key}")
    public ResponseEntity<Map<String, String>> deleteData(@PathVariable String key) {
        logger.info("Deleting data for key: {}", key);
        try {
            if (key == null || key.trim().isEmpty()) {
                logger.warn("Empty key provided in delete request");
                return ResponseEntity.badRequest().build();
            }
            Object removed = dataStore.remove(key);
            if (removed == null) {
                logger.warn("Data not found for key: {}", key);
                return ResponseEntity.notFound().build();
            }
            logger.info("Data deleted successfully for key: {}", key);
            return ResponseEntity.ok(Collections.singletonMap("message", "Data deleted successfully"));
        } catch (Exception e) {
            logger.error("Error deleting data for key: {}", key, e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).build();
        }
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<Map<String, String>> handleException(Exception e) {
        logger.error("Unexpected error occurred", e);
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(Collections.singletonMap("error", "Internal server error"));
    }

    @Valid
    public static class DataRequest {
        private String key;
        private Object value;

        public String getKey() {
            return key;
        }

        public void setKey(String key) {
            this.key = key;
        }

        public Object getValue() {
            return value;
        }

        public void setValue(Object value) {
            this.value = value;
        }
    }
}